import React, { useEffect, useRef, useState } from 'react';
import { Shield, Leaf, Gem, Users } from 'lucide-react';

const pillars = [
  {
    icon: Gem,
    title: 'Luxury Redefined',
    desc: 'Every detail is curated to exceed expectation — from architectural form to interior finishes, each space is a work of art.',
  },
  {
    icon: Leaf,
    title: 'Sustainable Living',
    desc: 'Incorporating smart, eco-conscious systems that reduce environmental footprint without compromising comfort or elegance.',
  },
  {
    icon: Shield,
    title: 'Uncompromising Quality',
    desc: 'Partnering with world-class engineering consultants like EGEC to ensure every structural and safety standard is exceeded.',
  },
  {
    icon: Users,
    title: 'Community First',
    desc: 'Designing spaces that foster connection — commercial centers, entertainment zones, and green corridors that bring people together.',
  },
];

export default function Vision() {
  const [visible, setVisible] = useState(false);
  const ref = useRef();

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => { if (entry.isIntersecting) setVisible(true); },
      { threshold: 0.1 }
    );
    if (ref.current) observer.observe(ref.current);
    return () => observer.disconnect();
  }, []);

  return (
    <section id="vision" ref={ref} style={{
      padding: '140px 0',
      background: 'var(--navy-deep)',
      position: 'relative',
      overflow: 'hidden',
    }}>
      {/* Diagonal band */}
      <div style={{
        position: 'absolute',
        top: 0, left: 0, right: 0, bottom: 0,
        background: 'linear-gradient(135deg, transparent 60%, rgba(201,169,110,0.04) 100%)',
        pointerEvents: 'none',
      }} />

      {/* Grid lines */}
      <div style={{
        position: 'absolute', inset: 0,
        backgroundImage: 'linear-gradient(rgba(255,255,255,0.02) 1px, transparent 1px), linear-gradient(90deg, rgba(255,255,255,0.02) 1px, transparent 1px)',
        backgroundSize: '80px 80px',
        pointerEvents: 'none',
      }} />

      <div className="container">
        {/* Header */}
        <div style={{ textAlign: 'center', marginBottom: '100px' }}>
          <div style={{
            display: 'inline-flex', alignItems: 'center', gap: '12px',
            marginBottom: '24px',
            opacity: visible ? 1 : 0,
            transition: 'opacity 0.8s ease',
          }}>
            <div style={{ width: '32px', height: '1px', background: 'var(--gold)' }} />
            <span style={{ fontFamily: 'var(--font-body)', fontSize: '11px', letterSpacing: '0.3em', color: 'var(--gold)', textTransform: 'uppercase', fontWeight: 500 }}>Our Vision</span>
            <div style={{ width: '32px', height: '1px', background: 'var(--gold)' }} />
          </div>

          <h2 style={{
            fontFamily: 'var(--font-display)',
            fontSize: 'clamp(44px, 5vw, 72px)',
            fontWeight: 300,
            lineHeight: 1.05,
            color: 'var(--white)',
            letterSpacing: '-0.02em',
            marginBottom: '24px',
            opacity: visible ? 1 : 0,
            transform: visible ? 'translateY(0)' : 'translateY(30px)',
            transition: 'all 0.8s var(--ease-out) 0.2s',
          }}>
            Four Pillars of<br />
            <em style={{ color: 'var(--gold)', fontStyle: 'italic' }}>Excellence</em>
          </h2>

          <p style={{
            fontFamily: 'var(--font-body)',
            fontSize: '16px',
            fontWeight: 300,
            lineHeight: 1.8,
            color: 'var(--white-70)',
            maxWidth: '560px',
            margin: '0 auto',
            opacity: visible ? 1 : 0,
            transition: 'opacity 0.8s ease 0.4s',
          }}>
            ADVA's approach to development is guided by four foundational principles that shape every decision, every design, and every delivery.
          </p>
        </div>

        {/* Pillars grid */}
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(4, 1fr)',
          gap: '2px',
        }}>
          {pillars.map((pillar, i) => {
            const Icon = pillar.icon;
            return (
              <PillarCard key={i} pillar={pillar} Icon={Icon} index={i} visible={visible} />
            );
          })}
        </div>

        {/* Bottom feature strip */}
        <div style={{
          marginTop: '80px',
          padding: '60px',
          background: 'linear-gradient(135deg, rgba(26,51,88,0.5) 0%, rgba(30,63,110,0.3) 100%)',
          border: '1px solid rgba(201,169,110,0.15)',
          display: 'grid',
          gridTemplateColumns: '1fr auto 1fr',
          gap: '60px',
          alignItems: 'center',
          opacity: visible ? 1 : 0,
          transform: visible ? 'translateY(0)' : 'translateY(30px)',
          transition: 'all 0.9s var(--ease-out) 0.8s',
        }}>
          <div>
            <div style={{ fontFamily: 'var(--font-display)', fontSize: '48px', fontWeight: 500, color: 'var(--gold)', lineHeight: 1, marginBottom: '8px' }}>EGP 800M</div>
            <div style={{ fontFamily: 'var(--font-body)', fontSize: '11px', letterSpacing: '0.2em', color: 'var(--white-70)', textTransform: 'uppercase' }}>Total Sales — ADVIDA Project</div>
          </div>

          <div style={{ width: '1px', height: '80px', background: 'rgba(201,169,110,0.2)' }} />

          <div>
            <p style={{ fontFamily: 'var(--font-display)', fontSize: '22px', fontWeight: 300, fontStyle: 'italic', color: 'var(--white)', lineHeight: 1.5, marginBottom: '16px' }}>
              "We are thrilled to continue our mission of transforming the luxury real estate landscape — now in Oman."
            </p>
            <div style={{ fontFamily: 'var(--font-body)', fontSize: '11px', letterSpacing: '0.2em', color: 'var(--gold)', textTransform: 'uppercase' }}>
              Ahmed El-Shennawy · Chairman & CEO
            </div>
          </div>
        </div>
      </div>

      <style>{`
        @media (max-width: 1100px) {
          #vision .container > div:nth-child(2) { grid-template-columns: repeat(2,1fr) !important; }
          #vision .container > div:last-child { grid-template-columns: 1fr !important; }
          #vision .container > div:last-child > div:nth-child(2) { display: none; }
        }
        @media (max-width: 600px) {
          #vision .container > div:nth-child(2) { grid-template-columns: 1fr !important; }
        }
      `}</style>
    </section>
  );
}

function PillarCard({ pillar, Icon, index, visible }) {
  const [hovered, setHovered] = useState(false);

  return (
    <div
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      style={{
        padding: '56px 40px',
        background: hovered ? 'rgba(201,169,110,0.06)' : 'rgba(255,255,255,0.03)',
        border: `1px solid ${hovered ? 'rgba(201,169,110,0.3)' : 'rgba(255,255,255,0.06)'}`,
        transition: 'all 0.4s ease',
        cursor: 'default',
        opacity: visible ? 1 : 0,
        transform: visible ? 'translateY(0)' : 'translateY(40px)',
        transitionDelay: `${0.2 + index * 0.15}s`,
      }}>
      <div style={{
        width: '56px', height: '56px',
        border: `1px solid ${hovered ? 'var(--gold)' : 'rgba(201,169,110,0.3)'}`,
        display: 'flex', alignItems: 'center', justifyContent: 'center',
        marginBottom: '32px',
        transition: 'all 0.3s ease',
        background: hovered ? 'rgba(201,169,110,0.08)' : 'transparent',
      }}>
        <Icon size={22} color={hovered ? 'var(--gold)' : 'rgba(201,169,110,0.6)'} />
      </div>

      <h3 style={{
        fontFamily: 'var(--font-heading)',
        fontSize: '20px',
        fontWeight: 500,
        color: hovered ? 'var(--white)' : 'var(--white-90)',
        marginBottom: '16px',
        transition: 'color 0.3s',
        letterSpacing: '0.01em',
      }}>{pillar.title}</h3>

      <p style={{
        fontFamily: 'var(--font-body)',
        fontSize: '14px',
        fontWeight: 300,
        lineHeight: 1.8,
        color: 'var(--white-70)',
      }}>{pillar.desc}</p>
    </div>
  );
}
